package operators;

public class Logicaloperator {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		//logical operators are used to combine boolean expression
				//&&,||,!
				int a=3;
				int b=2;
				System.out.println((a>b)&&(a==b));
				System.out.println((a>b)||(a==b));
				System.out.println(!(a==b));

	}

}
